static inline void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

static inline void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

static inline void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

static inline void show_progress_done(void) { flushed_printf("\n"); }

template <typename T>
static inline void do_not_optimize(const T& value) {
#if defined(__GNUC__)
  asm volatile("" : : "g"(value) : "memory");
#else
  volatile T sink = value;
  (void)sink;
#endif
}

template <typename Func>
static double benchmark_best_of_3(Func&& func) {
  double best_ms = 1e300;
  for (int i = 0; i < 3; i++) {
    const auto ts_start = std::chrono::high_resolution_clock::now();
    func();
    const auto ts_end = std::chrono::high_resolution_clock::now();
    const double duration_ms =
        std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
    if (duration_ms < best_ms) best_ms = duration_ms;
  }
  return best_ms;
}

template <typename T>
static void kernel_scalar(T seed,
                          T* g_data,
                          long size,
                          size_t workgroupsize,
                          unsigned int elements_per_wi,
                          unsigned int fusion_degree,
                          int compute_iters,
                          bool block_strided) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const long stride =
      block_strided ? static_cast<long>(workgroupsize) : compute_grid_size;
  const long big_stride = compute_grid_size * static_cast<long>(elements_per_wi);

#pragma omp parallel for schedule(static)
  for (long gid = 0; gid < compute_grid_size; gid++) {
    T tmps[64];
    const long idx = block_strided
                         ? ((gid / static_cast<long>(workgroupsize)) *
                                static_cast<long>(workgroupsize) *
                                static_cast<long>(elements_per_wi) +
                            (gid % static_cast<long>(workgroupsize)))
                         : gid;

    for (unsigned int k = 0; k < fusion_degree; k++) {
      for (unsigned int j = 0; j < elements_per_wi; j++) {
        tmps[j] = g_data[idx + static_cast<long>(j) * stride +
                         static_cast<long>(k) * big_stride];
        for (int i = 0; i < compute_iters; i++) {
          tmps[j] = tmps[j] * tmps[j] + seed;
        }
      }

      T sum = static_cast<T>(0);
      for (unsigned int j = 0; j + 1 < elements_per_wi; j += 2) {
        sum += tmps[j] * tmps[j + 1];
      }

      do_not_optimize(sum);

      if (sum == static_cast<T>(-1)) {
        g_data[idx + static_cast<long>(k) * big_stride] = sum;
      }
    }
  }
}

