struct Half2 {
  float x;
  float y;
};

static inline Half2 operator+(Half2 a, Half2 b) { return Half2{a.x + b.x, a.y + b.y}; }
static inline Half2 operator*(Half2 a, Half2 b) { return Half2{a.x * b.x, a.y * b.y}; }

static void kernel_half2(Half2 seed,
                         uint32_t* g_data,
                         long size,
                         size_t workgroupsize,
                         unsigned int elements_per_wi,
                         unsigned int fusion_degree,
                         int compute_iters,
                         bool block_strided) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const long stride =
      block_strided ? static_cast<long>(workgroupsize) : compute_grid_size;
  const long big_stride = compute_grid_size * static_cast<long>(elements_per_wi);

#pragma omp parallel for schedule(static)
  for (long gid = 0; gid < compute_grid_size; gid++) {
    Half2 tmps[64];
    const long idx = block_strided
                         ? ((gid / static_cast<long>(workgroupsize)) *
                                static_cast<long>(workgroupsize) *
                                static_cast<long>(elements_per_wi) +
                            (gid % static_cast<long>(workgroupsize)))
                         : gid;

    for (unsigned int k = 0; k < fusion_degree; k++) {
      for (unsigned int j = 0; j < elements_per_wi; j++) {
        const uint32_t raw =
            g_data[idx + static_cast<long>(j) * stride +
                   static_cast<long>(k) * big_stride];
        (void)raw;
        tmps[j] = Half2{0.0f, 0.0f};
        for (int i = 0; i < compute_iters; i++) {
          tmps[j] = tmps[j] * tmps[j] + seed;
        }
      }

      Half2 sum{0.0f, 0.0f};
      for (unsigned int j = 0; j + 1 < elements_per_wi; j += 2) {
        sum = sum + tmps[j] * tmps[j + 1];
      }

      do_not_optimize(sum.x);
      do_not_optimize(sum.y);

      if (sum.x == -1.0f && sum.y == -1.0f) {
        g_data[idx + static_cast<long>(k) * big_stride] = 0xBC00BC00u;
      }
    }
  }
}

static void runbench_warmup(unsigned char* buffer, long size) {
  const long reduced_grid_size = size / 256;
  uint16_t* data = reinterpret_cast<uint16_t*>(buffer);

#pragma omp parallel for schedule(static)
  for (long i = 0; i < reduced_grid_size; i++) {
    uint16_t v = data[i];
    do_not_optimize(v);
  }
}

static void runbench(const int compute_iterations[],
                     unsigned int krn_idx,
                     unsigned char* buffer,
                     long size,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool block_strided) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const int current_compute_iterations = compute_iterations[krn_idx];
  const long long computations =
      (elements_per_wi * static_cast<long long>(compute_grid_size) +
       (2LL * elements_per_wi * current_compute_iterations) *
           static_cast<long long>(compute_grid_size)) *
      fusion_degree;
  const long long memoryoperations = size;

  float* data_f = reinterpret_cast<float*>(buffer);
  double* data_d = reinterpret_cast<double*>(buffer);
  uint32_t* data_i = reinterpret_cast<uint32_t*>(buffer);
  uint32_t* data_h = reinterpret_cast<uint32_t*>(buffer);

  const double kernel_time_mad_sp = benchmark_best_of_3([&]() {
    kernel_scalar<float>(1.0f, data_f, size, workgroupsize, elements_per_wi,
                         fusion_degree, current_compute_iterations,
                         block_strided);
  });

  const double kernel_time_mad_dp = benchmark_best_of_3([&]() {
    kernel_scalar<double>(1.0, data_d, size, workgroupsize, elements_per_wi,
                          fusion_degree, current_compute_iterations,
                          block_strided);
  });

  const double kernel_time_mad_hp = benchmark_best_of_3([&]() {
    kernel_half2(Half2{1.0f, 1.0f}, data_h, size, workgroupsize,
                 elements_per_wi, fusion_degree, current_compute_iterations,
                 block_strided);
  });

  const double kernel_time_mad_int = benchmark_best_of_3([&]() {
    kernel_int(1u, data_i, size, workgroupsize, elements_per_wi, fusion_degree,
               current_compute_iterations, block_strided);
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      static_cast<double>(computations) /
          (static_cast<double>(memoryoperations) * sizeof(float)),
      kernel_time_mad_sp,
      static_cast<double>(computations) / kernel_time_mad_sp * 1000.0 /
          static_cast<double>(1000 * 1000 * 1000),
      (static_cast<double>(memoryoperations) * sizeof(float)) /
          kernel_time_mad_sp * 1000.0 / (1000.0 * 1000.0 * 1000.0),
      static_cast<double>(computations) /
          (static_cast<double>(memoryoperations) * sizeof(double)),
      kernel_time_mad_dp,
      static_cast<double>(computations) / kernel_time_mad_dp * 1000.0 /
          static_cast<double>(1000 * 1000 * 1000),
      (static_cast<double>(memoryoperations) * sizeof(double)) /
          kernel_time_mad_dp * 1000.0 / (1000.0 * 1000.0 * 1000.0),
      (2.0 * static_cast<double>(computations)) /
          (static_cast<double>(memoryoperations) * sizeof(uint32_t)),
      kernel_time_mad_hp,
      (2.0 * static_cast<double>(computations)) / kernel_time_mad_hp * 1000.0 /
          static_cast<double>(1000 * 1000 * 1000),
      (static_cast<double>(memoryoperations) * sizeof(uint32_t)) /
          kernel_time_mad_hp * 1000.0 / (1000.0 * 1000.0 * 1000.0),
      static_cast<double>(computations) /
          (static_cast<double>(memoryoperations) * sizeof(int)),
      kernel_time_mad_int,
      static_cast<double>(computations) / kernel_time_mad_int * 1000.0 /
          static_cast<double>(1000 * 1000 * 1000),
      (static_cast<double>(memoryoperations) * sizeof(int)) /
          kernel_time_mad_int * 1000.0 / (1000.0 * 1000.0 * 1000.0));
}

void mixbenchCPU(void* buffer_void, size_t size_bytes) {
  unsigned char* buffer = static_cast<unsigned char*>(buffer_void);
  const long size = static_cast<long>(size_bytes / sizeof(double));

  const bool block_strided = false;
  const bool host_allocated = true;
  const bool use_os_timer = true;
  const size_t workgroupsize = 256;
  const unsigned int elements_per_wi = 8;
  const unsigned int fusion_degree = 4;

  printf("Buffer size:            %zuMB\n", size_bytes / (1024 * 1024));
  printf("Workgroup size:         %d\n", static_cast<int>(workgroupsize));
  printf("Elements per workitem:  %d\n", elements_per_wi);
  printf("Workitem fusion degree: %d\n", fusion_degree);
  printf("Workitem stride:        %s\n", block_strided ? "Workgroup" : "NDRange");
  printf("Buffer allocation:      %s\n",
         host_allocated ? "Host allocated" : "Device allocated");
  printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CL event based");

  std::memset(buffer, 0, size_bytes);

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    show_progress_step(0, '/');
    show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  runbench_warmup(buffer, size);

  printf(
      "------------------------------------------------------------------------"
      "----- CSV data "
      "------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench(compute_iterations, i, buffer, size, workgroupsize,
             elements_per_wi, fusion_degree, block_strided);
  }

  printf(
      "------------------------------------------------------------------------"
      "------------------------------------------------------------------------"
      "--------------------\n");
}
